import{_ as a,o as t,i as r,aZ as i,b5 as l}from"./chunks/framework.D08fXB_e.js";const u=JSON.parse('{"title":"准备工作","description":"","frontmatter":{},"headers":[],"relativePath":"guide/ready.md","filePath":"guide/ready.md"}'),o={name:"guide/ready.md"};function s(n,e,m,h,p,d){return t(),r("div",null,[...e[0]||(e[0]=[i('<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /guide/ready.md for this page in Markdown format</div><h1 id="准备工作" tabindex="-1">准备工作 <a class="header-anchor" href="#准备工作" aria-label="Permalink to “准备工作”">​</a></h1><h2 id="源码" tabindex="-1">源码 <a class="header-anchor" href="#源码" aria-label="Permalink to “源码”">​</a></h2><p>阅读开发文档前，请确保手上已经有 One-step Console 源码，因为文档中提及的内容，都是需要在本地项目中编写或修改代码并运行才能呈现的。</p><h3 id="基础版" tabindex="-1">基础版 <a class="header-anchor" href="#基础版" aria-label="Permalink to “基础版”">​</a></h3><div class="tip custom-block"><p class="custom-block-title">发布助力</p><p><a href="https://github.com/one-step-admin/basic" target="_blank" rel="noreferrer"><img src="https://img.shields.io/github/stars/one-step-admin/basic?style=social" alt="star"></a></p><p><a href="https://gitee.com/one-step-admin/basic" target="_blank" rel="noreferrer"><img src="https://gitee.com/one-step-admin/basic/badge/star.svg?theme=dark" alt="star"></a></p><p>目前我们正专注服务付费用户以完善产品，一旦 Github 和 Gitee 均达到 500 Star 时，我们将提供开源基础版，并且也能有足够的信心进行长期维护。</p><p>如果你喜欢本产品，可以点个 ⭐ ，助力基础版更快问世，或者直接<a href="./../buy.html">购买专业版</a>，立即获取完整源码。</p></div><h3 id="专业版" tabindex="-1">专业版 <a class="header-anchor" href="#专业版" aria-label="Permalink to “专业版”">​</a></h3><p>专业版用户会被邀请加入到 <a href="https://github.com/one-step-admin" target="_blank" rel="noreferrer">One-step Console</a> Github 官方组织，加入组织后在专业版仓库 <a href="https://github.com/one-step-admin/pro/releases" target="_blank" rel="noreferrer">Releases</a> 页面下载最新版本的压缩包。</p><p>购买专业版点<a href="./../buy.html">这里</a>。</p><h2 id="开发环境" tabindex="-1">开发环境 <a class="header-anchor" href="#开发环境" aria-label="Permalink to “开发环境”">​</a></h2><p>使用本模板前，需要在本地依次安装好 <a href="https://nodejs.org/" target="_blank" rel="noreferrer">Node.js</a>, <a href="https://pnpm.io/zh/" target="_blank" rel="noreferrer">pnpm</a>, <a href="https://git-scm.com/" target="_blank" rel="noreferrer">Git</a>(非必须) 和 <a href="https://code.visualstudio.com/" target="_blank" rel="noreferrer">Visual Studio Code</a>。</p><div class="warning custom-block"><p class="custom-block-title">注意</p><ul><li>在 package.json 文件中有限制 node 要求版本，建议使用最新 LTS 版本。</li><li>如果你不想使用 VSCode ，我们也强烈建议你使用基于 VSCode 内核的 IDE ，如 <a href="https://www.cursor.com/" target="_blank" rel="noreferrer">Cursor</a> 。</li></ul></div><p>然后在 Visual Studio Code 里安装好以下扩展：</p><ul><li><a href="https://marketplace.visualstudio.com/items?itemName=EditorConfig.EditorConfig" target="_blank" rel="noreferrer">EditorConfig for VS Code</a></li><li><a href="https://marketplace.visualstudio.com/items?itemName=mikestead.dotenv" target="_blank" rel="noreferrer">DotENV</a></li><li><a href="https://marketplace.visualstudio.com/items?itemName=dbaeumer.vscode-eslint" target="_blank" rel="noreferrer">ESLint</a></li><li><a href="https://marketplace.visualstudio.com/items?itemName=stylelint.vscode-stylelint" target="_blank" rel="noreferrer">stylelint</a></li><li><a href="https://marketplace.visualstudio.com/items?itemName=Vue.volar" target="_blank" rel="noreferrer">Vue - Official</a></li><li><a href="https://marketplace.visualstudio.com/items?itemName=antfu.unocss" target="_blank" rel="noreferrer">UnoCSS</a></li></ul><p>在 Visual Studio Code 里打开源码文件夹，右下角会自动提示需要安装的依赖，直接点击安装即可。</p><p><img src="'+l+'" alt="" data-zoomable=""></p><div class="tip custom-block"><p class="custom-block-title">额外推荐</p><p>以上为开发时必备扩展，以下则是作者推荐安装的扩展，安装它们将在一定程度上提升开发效率。</p><ul><li><a href="https://marketplace.visualstudio.com/items?itemName=MS-CEINTL.vscode-language-pack-zh-hans" target="_blank" rel="noreferrer">Chinese (Simplified) Language Pack for Visual Studio Code</a> 中文语言包</li><li><a href="https://marketplace.visualstudio.com/items?itemName=antfu.pnpm-catalog-lens" target="_blank" rel="noreferrer">Catalog Lens</a> 显示PNPM/Yarn/Bun目录的嵌套版本</li><li><a href="https://marketplace.visualstudio.com/items?itemName=antfu.goto-alias" target="_blank" rel="noreferrer">Goto definition alias</a> 转到別名重定向后的定义</li><li><a href="https://marketplace.visualstudio.com/items?itemName=antfu.iconify" target="_blank" rel="noreferrer">Iconify IntelliSense</a> 在代码中预览 iconify 图标</li><li><a href="https://marketplace.visualstudio.com/items?itemName=naumovs.color-highlight" target="_blank" rel="noreferrer">Color Highlight</a> 在代码中高亮颜色</li><li><a href="https://marketplace.visualstudio.com/items?itemName=vincaslt.highlight-matching-tag" target="_blank" rel="noreferrer">Highlight Matching Tag</a> 高亮显示匹配的标签</li><li><a href="https://marketplace.visualstudio.com/items?itemName=kisstkondoros.vscode-gutter-preview" target="_blank" rel="noreferrer">Image preview</a> 图片预览</li><li><a href="https://marketplace.visualstudio.com/items?itemName=oderwat.indent-rainbow" target="_blank" rel="noreferrer">indent-rainbow</a> 彩虹缩进提示</li></ul></div><h2 id="技术栈" tabindex="-1">技术栈 <a class="header-anchor" href="#技术栈" aria-label="Permalink to “技术栈”">​</a></h2><p>了解并熟悉框架使用到的技术栈，能让你使用本框架更得心应手。</p><ul><li><a href="https://cn.vitejs.dev/" target="_blank" rel="noreferrer">Vite</a></li><li><a href="https://cn.vuejs.org/" target="_blank" rel="noreferrer">Vue 3</a></li><li><a href="https://router.vuejs.org/zh/" target="_blank" rel="noreferrer">Vue Router</a></li><li><a href="https://pinia.vuejs.org/zh/" target="_blank" rel="noreferrer">Pinia</a></li><li><a href="https://unocss.dev/" target="_blank" rel="noreferrer">UnoCSS</a></li></ul>',20)])])}const f=a(o,[["render",s]]);export{u as __pageData,f as default};
